import { mkdir, rm, writeFile } from 'node:fs/promises';
import { basename, resolve } from 'node:path';
import { scaffoldTemplates } from './scaffold/templates.js';
const PROJECT_NAME = /^[a-z0-9][a-z0-9-]*$/;
export async function createProject(name, cwd = process.cwd(), config) {
    const directory = resolve(cwd, name);
    const projectName = name === '.' ? basename(directory) : name;
    if (!PROJECT_NAME.test(projectName)) {
        throw new Error('Invalid project name');
    }
    if (name !== '.') {
        try {
            await mkdir(directory);
        }
        catch (error) {
            if (error.code === 'EEXIST') {
                throw new Error(`Project directory already exists: ${directory}`);
            }
            throw error;
        }
    }
    try {
        await Promise.all([
            mkdir(resolve(directory, 'branding/content'), { recursive: true }),
            mkdir(resolve(directory, 'branding/locales/en-US'), { recursive: true }),
            mkdir(resolve(directory, 'src/browser/assets'), { recursive: true }),
            mkdir(resolve(directory, 'src/browser/features'), { recursive: true }),
            mkdir(resolve(directory, 'src/browser/styles'), { recursive: true }),
            mkdir(resolve(directory, 'src/browser/views'), { recursive: true }),
            mkdir(resolve(directory, 'src/firefox'), { recursive: true }),
            mkdir(resolve(directory, 'prefs')),
            mkdir(resolve(directory, 'docs')),
            mkdir(resolve(directory, 'patches')),
        ]);
        await Promise.all(Object.entries(scaffoldTemplates(projectName, config)).map(([path, contents]) => writeFile(resolve(directory, path), contents, { flag: 'wx' })));
    }
    catch (error) {
        if (name !== '.')
            await rm(directory, { recursive: true, force: true });
        throw error;
    }
    return directory;
}
